class Solution {
public:
    long long validSubstringCount(string word1, string word2) {
        int m = word1.size(), n = word2.size();
        long long res = 0;
        int count[26] = {0}, match = 0;
        for (int i = 0; i < n - 1; i++) {
            count[word1[i] - 'a']++;
        }
        int left = 0;
        for (int right = 0; right < m; right++) {
            count[word1[right] - 'a']++;
            if (word1[right] == word2[right % n]) match++;
            while (match == n) {
                res += m - right;
                count[word1[left] - 'a']--;
                if (word1[left] == word2[left % n]) match--;
                left++;
            }
        }
        return res;
    }
};
```
